$data_i = [
    "active" => [
        ["algo" => 349, "uuid" => "546db8", "name" => "hkdf", "type" => "kdf", "status" => "active", "title" => "HKDF", "description_md" => "HKDF (HMAC-based Key Derivation Function) is defined in RFC 5869 by Krawczyk and Eronen. Provides a two-step Extract-then-Expand KDF using HMAC. Extract: PRK = HMAC-H(salt, IKM); Expand: OKM = HMAC-H(PRK, info || counter).\n\nHKDF is the standard KDF for TLS 1.3, Signal Protocol, WireGuard, Noise Protocol, HPKE, MLS, and essentially all modern cryptographic protocols. The `info` parameter provides domain separation. Use HKDF-SHA256 for standard security, HKDF-SHA3-256 for post-quantum.", "mental_model" => "RFC 5869 Extract-then-Expand KDF -- the standard for TLS 1.3, Signal, WireGuard.", "purpose" => ["key derivation", "key expansion", "subkey generation"], "good_for" => ["tls 1.3", "signal", "wireguard", "noise", "hpke", "mls", "session keys"], "avoid_for" => ["password hashing (use argon2id)", "entropy stretching without salt"], "pros" => ["rfc 5869 standard", "domain separation via info", "two-step extract+expand", "any hmac backend"], "cons" => ["not for low-entropy input without salt (use password kdf)"], "difficulty" => 1, "security" => 5, "quantum_impact" => "HMAC-SHA256 based: ~128-bit post-quantum. HKDF-SHA3-256 preferred for PQ.", "post_quantum_status" => 4, "example" => ["scenario" => "TLS 1.3 key schedule HKDF", "input" => ["ikm" => "shared_secret_from_ecdh", "salt" => "0x00...0", "info" => "tls13 finished"], "output" => ["okm" => "32-byte session key"]], "flow" => ["extract: PRK = HMAC-H(salt, IKM)", "expand: T(1) = HMAC-H(PRK, info||0x01)", "T(2) = HMAC-H(PRK, T(1)||info||0x02)", "OKM = T(1)||T(2)||..."], "related" => ["hkdf-expand", "hkdf-extract", "hkdf-expand-label"]],
        ["algo" => 350, "uuid" => "c3ec75", "name" => "hkdf-expand", "type" => "kdf", "status" => "active", "title" => "HKDF-Expand", "description_md" => "HKDF-Expand is the second step of HKDF. Takes a pseudorandom key (PRK from HKDF-Extract) and info context string to produce output key material of arbitrary length.\n\nHKDF-Expand is used directly in TLS 1.3 key schedule to derive multiple keys from a single PRK. The info string provides domain separation for different key types (handshake key, data key, etc.).", "mental_model" => "HKDF step 2 -- expand PRK to multiple keys using info domain separation.", "purpose" => ["multi-key derivation from prk"], "good_for" => ["tls 1.3 key schedule multiple keys", "domain separated subkeys"], "avoid_for" => ["direct use without extract (need high-entropy PRK)"], "pros" => ["arbitrary length output", "info domain separation", "tls 1.3 standard"], "cons" => ["requires high-entropy PRK as input"], "difficulty" => 1, "security" => 5, "quantum_impact" => "Same as HKDF.", "post_quantum_status" => 4, "example" => ["scenario" => "TLS 1.3 derive handshake keys", "input" => ["prk" => "32-byte prk from extract", "info" => "tls13 c hs traffic", "len" => "32"], "output" => ["key" => "32-byte handshake key"]], "flow" => ["T(1) = HMAC-H(PRK, info||0x01)", "T(i) = HMAC-H(PRK, T(i-1)||info||i)", "OKM = first L bytes of T(1)||T(2)||..."], "related" => ["hkdf", "hkdf-extract", "hkdf-expand-label"]],
        ["algo" => 351, "uuid" => "8ab2cb", "name" => "hkdf-extract", "type" => "kdf", "status" => "active", "title" => "HKDF-Extract", "description_md" => "HKDF-Extract is the first step of HKDF. Combines input key material (IKM) with a salt to produce a pseudorandom key (PRK) of fixed hash output length.\n\nHKDF-Extract is used to whiten and compress input key material from diverse sources (ECDH shared secrets, pre-shared keys, entropy pools). A random salt improves security when the IKM has limited entropy.", "mental_model" => "HKDF step 1 -- whiten/compress IKM into a PRK using salt.", "purpose" => ["ikm whitening", "entropy compression"], "good_for" => ["ecdh output whitening", "psk normalization"], "avoid_for" => ["password input without argon2 first"], "pros" => ["entropy extraction from diverse sources", "salt improves security"], "cons" => ["PRK only as good as IKM + salt entropy"], "difficulty" => 1, "security" => 5, "quantum_impact" => "HMAC-based; same as HKDF.", "post_quantum_status" => 4, "example" => ["scenario" => "TLS 1.3 extract from ECDH shared secret", "input" => ["salt" => "zeros or previous secret", "ikm" => "ecdh output X"], "output" => ["prk" => "32-byte prk"]], "flow" => ["PRK = HMAC-H(salt, IKM)"], "related" => ["hkdf", "hkdf-expand"]],
        ["algo" => 352, "uuid" => "bc005b", "name" => "hkdf-expand-label", "type" => "kdf", "status" => "active", "title" => "HKDF-ExpandLabel", "description_md" => "HKDF-ExpandLabel is the TLS 1.3-specific variant of HKDF-Expand defined in RFC 8446. Adds a structured label string 'tls13 ' prefix and transcript hash binding for context.\n\nHKDF-ExpandLabel provides TLS 1.3 domain separation with protocol-specific labels and transcript hash binding. Used throughout the TLS 1.3 key schedule to derive client/server keys, IVs, and finished MACs.", "mental_model" => "TLS 1.3 HKDF-Expand with 'tls13 ' label + transcript hash binding.", "purpose" => ["tls 1.3 key schedule"], "good_for" => ["tls 1.3 implementation key derivation"], "avoid_for" => ["non-tls (use hkdf-expand directly)"], "pros" => ["tls 1.3 rfc 8446 standard", "transcript bound", "protocol domain separation"], "cons" => ["tls-specific format"], "difficulty" => 2, "security" => 5, "quantum_impact" => "Same as HKDF.", "post_quantum_status" => 4, "example" => ["scenario" => "TLS 1.3 derive client_handshake_traffic_secret", "input" => ["secret" => "handshake_secret", "label" => "c hs traffic", "context" => "transcript_hash"], "output" => ["key" => "client_handshake_traffic_secret"]], "flow" => ["HkdfLabel = length || 'tls13 '||label || context", "HKDF-Expand(secret, HkdfLabel, length)"], "related" => ["hkdf", "hkdf-expand", "kdf-tls13"]],
        ["algo" => 353, "uuid" => "81dd39", "name" => "kdf-tls12", "type" => "kdf", "status" => "active", "title" => "TLS 1.2 PRF", "description_md" => "TLS 1.2 PRF is the key derivation function defined in RFC 5246 for TLS 1.2. Uses P_hash(secret, seed) = HMAC(secret, A(1)||seed) || HMAC(secret, A(2)||seed) || ... where A(i) = HMAC(secret, A(i-1)).\n\nTLS 1.2 PRF is used to derive master_secret from pre_master_secret and to expand keys. Uses HMAC-SHA256 or HMAC-SHA384 depending on cipher suite. Legacy -- TLS 1.3 uses HKDF.", "mental_model" => "TLS 1.2 HMAC-based PRF for master secret and key expansion -- legacy.", "purpose" => ["tls 1.2 key derivation"], "good_for" => ["tls 1.2 implementation", "legacy tls compatibility"], "avoid_for" => ["new protocols (use hkdf/tls 1.3)"], "pros" => ["rfc 5246 standard", "tls 1.2 required", "sha256/sha384 variants"], "cons" => ["legacy (tls 1.3 uses hkdf)", "complex p_hash construction"], "difficulty" => 2, "security" => 4, "quantum_impact" => "HMAC-SHA256 ~128-bit post-quantum.", "post_quantum_status" => 3, "example" => ["scenario" => "TLS 1.2 master secret derivation", "input" => ["pre_master_secret" => "pms bytes", "label" => "master secret", "seed" => "client_random||server_random"], "output" => ["master_secret" => "48 bytes"]], "flow" => ["P_hash = HMAC(S, A(1)||seed) || HMAC(S, A(2)||seed) || ...", "A(0) = seed; A(i) = HMAC(S, A(i-1))", "PRF(S, label, seed) = P_hash(S, label||seed)"], "related" => ["kdf-tls13", "hkdf", "hkdf-expand-label"]],
        ["algo" => 354, "uuid" => "245103", "name" => "kdf-tls13", "type" => "kdf", "status" => "active", "title" => "TLS 1.3 Key Schedule", "description_md" => "TLS 1.3 Key Schedule is the full HKDF-based key derivation pipeline defined in RFC 8446. Derives early, handshake, and application traffic secrets from PSK/ECDHE inputs using HKDF-Extract and HKDF-ExpandLabel.\n\nThe TLS 1.3 key schedule separates early data keys, handshake keys, and application keys. Forward secrecy is built into every session. All keys are transcript-bound. This is the reference design for modern KDF pipelines.", "mental_model" => "TLS 1.3 full HKDF pipeline: early/handshake/application secrets -- gold standard.", "purpose" => ["tls 1.3 session key derivation"], "good_for" => ["tls 1.3 implementation", "kdf pipeline design reference"], "avoid_for" => ["direct use outside tls (use hkdf)"], "pros" => ["forward secrecy", "transcript bound", "rfc 8446 standard", "psk + ecdhe combined"], "cons" => ["complex multi-step pipeline"], "difficulty" => 3, "security" => 5, "quantum_impact" => "HKDF-SHA256 based: ~128-bit PQ. HKDF-SHA384 for 256-bit.", "post_quantum_status" => 4, "example" => ["scenario" => "TLS 1.3 handshake key derivation", "input" => ["ecdh_secret" => "shared_secret", "client_hello_random" => "..."], "output" => ["client_write_key" => "32 bytes", "client_write_iv" => "12 bytes"]], "flow" => ["early secret = HKDF-Extract(0, PSK_or_0)", "handshake secret = HKDF-Extract(derived_secret, ecdhe)", "master secret = HKDF-Extract(derived_secret, 0)", "traffic keys via ExpandLabel"], "related" => ["hkdf-expand-label", "hkdf", "kdf-tls12"]],
        ["algo" => 355, "uuid" => "8811e0", "name" => "kdf-ssh", "type" => "kdf", "status" => "active", "title" => "SSH KDF", "description_md" => "SSH KDF is the key derivation mechanism defined in RFC 4253 for SSH-2. Derives encryption keys, IV, and MAC keys from the shared secret K and session hash H using H(K||H||letter||session_id).\n\nSSH KDF uses simple hash-based PRF with letter identifiers ('A' through 'F') for different key types. Less flexible than HKDF but standardized for SSH-2. RSA/ECDH shared secrets are fed through SHA-1 or SHA-256 depending on kex algorithm.", "mental_model" => "SSH-2 letter-keyed hash KDF for encryption/MAC/IV -- RFC 4253 standard.", "purpose" => ["ssh-2 session key derivation"], "good_for" => ["ssh-2 implementation"], "avoid_for" => ["non-ssh (use hkdf)"], "pros" => ["rfc 4253 standard", "ssh-2 required"], "cons" => ["simple non-salt construction", "sha-1 in old kex modes"], "difficulty" => 2, "security" => 4, "quantum_impact" => "SHA-256 based ~128-bit PQ for modern SSH.", "post_quantum_status" => 3, "example" => ["scenario" => "SSH-2 derive encryption key A", "input" => ["K" => "shared_secret", "H" => "session_hash", "letter" => "A", "session_id" => "..."], "output" => ["key_A" => "derived encryption key"]], "flow" => ["K1 = H(K || H || letter || session_id)", "K2 = H(K || H || K1) if more bytes needed", "keys A-F derived with different letters"], "related" => ["hkdf", "kdf-tls13"]],
        ["algo" => 356, "uuid" => "1c9a03", "name" => "kdf-ikev1", "type" => "kdf", "status" => "active", "title" => "IKEv1 KDF", "description_md" => "IKEv1 KDF is the key derivation mechanism in Internet Key Exchange version 1 (RFC 2409). Uses prf(prf(Ni_b || Nr_b, g^xy), ...) chains to derive SKEYID and subsequent keys.\n\nIKEv1 KDF is the legacy key schedule for IPsec Phase 1 and Phase 2. Contains complex multi-step derivations. Superseded by IKEv2 (RFC 7296) which uses a cleaner HKDF-like prf+ construct. Still required for legacy VPN compatibility.", "mental_model" => "IKEv1 legacy IPsec Phase 1/2 prf-chain KDF -- superseded by IKEv2.", "purpose" => ["ikev1 legacy ipsec kdf"], "good_for" => ["legacy ikev1 vpn compatibility"], "avoid_for" => ["new designs (use ikev2 kdf)"], "pros" => ["rfc 2409 standard", "ikev1 required for legacy"], "cons" => ["complex prf chain", "superseded by ikev2"], "difficulty" => 3, "security" => 4, "quantum_impact" => "DH/hash dependent; modern ikev1 variants ~128-bit PQ.", "post_quantum_status" => 3, "example" => ["scenario" => "IKEv1 Phase 1 SKEYID derivation", "input" => ["Ni_b" => "initiator nonce", "Nr_b" => "responder nonce", "g_xy" => "dh shared secret"], "output" => ["SKEYID" => "prf(Ni_b||Nr_b, g_xy)"]], "flow" => ["SKEYID = prf(Ni||Nr, g^xy)", "SKEYID_d = prf(SKEYID, g^xy||CKY-I||CKY-R||0)", "SKEYID_a = prf(SKEYID, SKEYID_d||...)", "SKEYID_e = prf(SKEYID, SKEYID_a||...)"], "related" => ["kdf-ikev2", "hkdf"]],
        ["algo" => 357, "uuid" => "2a5e34", "name" => "kdf-ikev2", "type" => "kdf", "status" => "active", "title" => "IKEv2 KDF", "description_md" => "IKEv2 KDF uses the prf+ construct defined in RFC 7296. prf+(K, S) = T1 || T2 || T3... where T1 = prf(K, S||0x01), T(i) = prf(K, T(i-1)||S||i). Cleaner than IKEv1 KDF.\n\nIKEv2 is the current IPsec standard. Its prf+ construct is similar to HKDF-Expand. Used to derive IKE SA keys, Child SA keys, and EAP keys. Modern IKEv2 uses HMAC-SHA256 or AES-CMAC-PRF-128.", "mental_model" => "IKEv2 prf+ counter KDF for IPsec SA keys -- cleaner than IKEv1, HKDF-Expand analog.", "purpose" => ["ikev2 ipsec sa key derivation"], "good_for" => ["ikev2 vpn implementation", "ipsec ike sa keys"], "avoid_for" => ["non-ipsec (use hkdf)"], "pros" => ["rfc 7296 standard", "cleaner than ikev1", "prf+ extensible length"], "cons" => ["ipsec-specific"], "difficulty" => 2, "security" => 5, "quantum_impact" => "HMAC-SHA256 ~128-bit PQ.", "post_quantum_status" => 4, "example" => ["scenario" => "IKEv2 Child SA key derivation", "input" => ["K" => "skeyseed", "S" => "Ni||Nr||SPIi||SPIr"], "output" => ["keys" => "SK_d, SK_ai, SK_ar, SK_ei, SK_er"]], "flow" => ["prf+(K, S) = prf(K, S||0x01) || prf(K, prev||S||0x02) || ...", "slice output into key blocks"], "related" => ["kdf-ikev1", "hkdf-expand", "aes-cmac-prf-128"]],
        ["algo" => 358, "uuid" => "ab5fef", "name" => "kdf-srtp", "type" => "kdf", "status" => "active", "title" => "SRTP KDF", "description_md" => "SRTP KDF is the key derivation function for Secure Real-time Transport Protocol defined in RFC 3711. Derives session keys for encryption and authentication from a master key using AES in counter mode as a PRF.\n\nSRTP KDF derives three types of session keys (cipher key, salt, auth key) from a master key and master salt. Used in VoIP (SIP/SRTP), WebRTC, and real-time media security.", "mental_model" => "AES-CTR PRF key derivation for SRTP VoIP/WebRTC media keys.", "purpose" => ["srtp voip key derivation", "webrtc media key derivation"], "good_for" => ["sip/srtp voip", "webrtc dtls-srtp keys"], "avoid_for" => ["non-srtp (use hkdf)"], "pros" => ["rfc 3711 standard", "aes-ctr prf", "three-key derivation"], "cons" => ["srtp-specific", "aes-ctr prf less flexible than hkdf"], "difficulty" => 2, "security" => 5, "quantum_impact" => "AES-128 based; ~64-bit post-quantum.", "post_quantum_status" => 3, "example" => ["scenario" => "WebRTC SRTP session key derivation", "input" => ["master_key" => "E1F97A0D3E018BE0D64FA32C06DE4139", "master_salt" => "0EC675AD498AFEEBB6960B3AABE6", "label" => "cipher"], "output" => ["session_key" => "aes-ctr derived key"]], "flow" => ["x = label * 2^48 XOR master_salt", "aes-ctr prf over x with master_key", "slice for cipher_key, salt, auth_key"], "related" => ["hkdf", "kdf-tls13"]],
        ["algo" => 359, "uuid" => "c75766", "name" => "kdf-sp800-108", "type" => "kdf", "status" => "active", "title" => "NIST SP 800-108 KDF", "description_md" => "NIST SP 800-108 defines standard KDF modes using PRFs: counter mode, feedback mode, and double-pipeline mode. Uses HMAC or AES-CMAC as the PRF.\n\nSP 800-108 KDFs are used in NIST-compliant federal cryptography systems, KMIP protocols, and enterprise key management. Counter mode is simplest: K_i = PRF(K_master, i || Label || 0x00 || Context || L).", "mental_model" => "NIST SP 800-108 standard KDF modes (counter/feedback/double-pipeline) for federal compliance.", "purpose" => ["nist fips kdf", "enterprise key management", "federal compliance kdf"], "good_for" => ["nist fips compliance", "kmip enterprise kms", "federal key derivation"], "avoid_for" => ["protocol kdf (use hkdf for tls/signal)"], "pros" => ["nist sp 800-108 standard", "multiple prf backends", "counter/feedback modes"], "cons" => ["less flexible than hkdf", "mainly for compliance scenarios"], "difficulty" => 2, "security" => 5, "quantum_impact" => "HMAC-SHA256 backend ~128-bit PQ.", "post_quantum_status" => 4, "example" => ["scenario" => "Federal KMS subkey derivation", "input" => ["K_master" => "master key", "label" => "encryption", "context" => "KeyID=0001", "len" => "256"], "output" => ["derived_key" => "256-bit key"]], "flow" => ["counter mode: K_i = PRF(K, i || Label || 0x00 || Context || L)", "feedback mode: K_i = PRF(K, K_(i-1) || ...)", "concatenate K_1 || K_2 ... slice to L bits"], "related" => ["hkdf", "hkdf-expand", "aes-cmac"]],
        ["algo" => 360, "uuid" => "480e07", "name" => "kda-onestep", "type" => "kdf", "status" => "active", "title" => "One-Step KDA", "description_md" => "One-Step KDA (Key Derivation Algorithm) is defined in NIST SP 800-56C Rev 2 as a single-step key derivation using a hash or HMAC. Combines shared secret Z with OtherInput to produce key material: K = H(counter || Z || OtherInfo).\n\nOne-Step KDA is used in NIST-compliant key agreement schemes (ECDH, RSA-KEM) to derive session keys from the raw shared secret. Used in CMS (RFC 5652), KMIP, and NIST SP 800-56A compliant implementations.", "mental_model" => "NIST SP 800-56C single-step hash KDF for ECDH/RSA-KEM session keys.", "purpose" => ["nist key agreement kdf", "ecdh session key"], "good_for" => ["nist sp 800-56a ecdh", "cms rfc 5652 key wrap", "federal key agreement"], "avoid_for" => ["non-nist-compliance (use hkdf x963-kdf)"], "pros" => ["nist sp 800-56c standard", "simple single pass", "hash or hmac backend"], "cons" => ["less flexible than hkdf", "compliance-focused"], "difficulty" => 2, "security" => 5, "quantum_impact" => "Hash dependent; SHA-256 ~128-bit PQ.", "post_quantum_status" => 4, "example" => ["scenario" => "ECDH NIST SP 800-56C session key", "input" => ["Z" => "ecdh shared secret", "OtherInfo" => "algorithm_id||party_uinfo||party_vinfo"], "output" => ["K" => "derived session key"]], "flow" => ["counter = 0x00000001", "K(1) = H(counter || Z || OtherInfo)", "increment counter until L bits derived"], "related" => ["kda-twostep", "hkdf", "x963-kdf", "concat-kdf"]],
        ["algo" => 361, "uuid" => "81a3f5", "name" => "kda-twostep", "type" => "kdf", "status" => "active", "title" => "Two-Step KDA", "description_md" => "Two-Step KDA is defined in NIST SP 800-56C Rev 2 as an Extract-then-Expand KDF using HMAC. Step 1: PRK = HMAC(salt, Z || OtherInfo); Step 2: expand using SP 800-108 feedback or counter mode.\n\nTwo-Step KDA is the NIST-standard equivalent of HKDF but with SP 800-108 expand step. Used in NIST-compliant post-quantum key agreement protocols.", "mental_model" => "NIST SP 800-56C extract+SP800-108-expand KDA -- HKDF analog for NIST compliance.", "purpose" => ["nist compliant hkdf alternative"], "good_for" => ["nist sp 800-56c pq protocol kdf", "federal post-quantum compliance"], "avoid_for" => ["general use (hkdf simpler and equivalent)"], "pros" => ["nist sp 800-56c standard", "extract+expand structure", "pq protocol support"], "cons" => ["more complex than hkdf", "compliance-only niche"], "difficulty" => 3, "security" => 5, "quantum_impact" => "HMAC-SHA256 ~128-bit PQ.", "post_quantum_status" => 4, "example" => ["scenario" => "NIST PQ KEM key derivation two-step", "input" => ["Z" => "ml-kem shared secret", "salt" => "random bytes"], "output" => ["K" => "derived key"]], "flow" => ["step 1: PRK = HMAC(salt, Z||OtherInfo)", "step 2: SP 800-108 counter or feedback mode expand"], "related" => ["kda-onestep", "hkdf", "kdf-sp800-108"]],
        ["algo" => 362, "uuid" => "db1815", "name" => "concat-kdf", "type" => "kdf", "status" => "active", "title" => "Concat KDF", "description_md" => "Concat KDF is a simple key derivation function that concatenates a counter, the shared secret Z, and OtherInfo before hashing: K = H(counter || Z || OtherInfo). Defined in NIST SP 800-56A (Appendix C) and used in JWA RFC 7518 for ECDH-ES.\n\nConcat KDF is the default KDF in JSON Web Algorithms (JWA) for ECDH-ES key agreement. Also used in XML Encryption and some S/MIME implementations. Simple but non-extensible compared to HKDF.", "mental_model" => "Single-step concat hash KDF -- JWA ECDH-ES standard (RFC 7518).", "purpose" => ["jwa ecdh-es key wrap kdf", "xml encryption kdf"], "good_for" => ["jwe ecdh-es key derivation", "rfc 7518 jwa", "xml encryption"], "avoid_for" => ["new designs (hkdf more flexible)"], "pros" => ["rfc 7518 jwa standard", "simple single hash", "ecdh-es standard"], "cons" => ["non-extensible", "less flexible than hkdf"], "difficulty" => 1, "security" => 4, "quantum_impact" => "SHA-256 based; ~128-bit PQ.", "post_quantum_status" => 4, "example" => ["scenario" => "JWE ECDH-ES key derivation", "input" => ["Z" => "ecdh shared secret X bytes", "OtherInfo" => "A128KW||partyUInfo||partyVInfo||128"], "output" => ["key_data" => "16 bytes AES-128 key"]], "flow" => ["counter = 00000001", "K = SHA-256(counter || Z || alg_id_len || alg_id || pu_len || pu || pv_len || pv || L)"], "related" => ["hkdf", "x963-kdf", "kda-onestep"]],
        ["algo" => 363, "uuid" => "bc9019", "name" => "x942-kdf", "type" => "kdf", "status" => "active", "title" => "X9.42 KDF", "description_md" => "X9.42 KDF is a key derivation function defined in ANSI X9.42 for Diffie-Hellman key agreement. Uses a hash-based counter mode similar to Concat KDF but with X9.42 OtherInfo structure.\n\nX9.42 KDF is used in CMS (RFC 5652) for AES key wrap with DH key agreement, and in legacy S/MIME, XML Encryption. Largely replaced by HKDF or Concat KDF in modern systems.", "mental_model" => "ANSI X9.42 DH key agreement hash KDF -- CMS legacy, replaced by concat KDF/HKDF.", "purpose" => ["ansi x9.42 dh key wrap kdf"], "good_for" => ["cms rfc 5652 dh key wrap", "legacy s/mime"], "avoid_for" => ["new designs (use hkdf or concat-kdf)"], "pros" => ["ansi x9.42 standard", "cms compatible"], "cons" => ["legacy", "replaced by concat kdf/hkdf"], "difficulty" => 2, "security" => 4, "quantum_impact" => "Hash dependent; SHA-256 ~128-bit PQ.", "post_quantum_status" => 3, "example" => ["scenario" => "CMS DH key wrap X9.42 KDF", "input" => ["Z" => "dh shared secret", "OtherInfo_x942" => "ansi x9.42 structure"], "output" => ["wrapped_key_material" => "derived key"]], "flow" => ["counter = 00000001 (big-endian)", "K(i) = H(Z || counter || OtherInfo)", "concatenate until L bits"], "related" => ["concat-kdf", "hkdf", "kda-onestep"]],
        ["algo" => 364, "uuid" => "82d4e2", "name" => "x963-kdf", "type" => "kdf", "status" => "active", "title" => "X9.63 KDF", "description_md" => "X9.63 KDF is a key derivation function defined in ANSI X9.63 for elliptic curve key agreement. Uses SHA-hash of Z || counter || SharedInfo: K = H(Z || counter || SharedInfo).\n\nX9.63 KDF is used in ECIES (ISO 18033-2), ANSI X9.63 ECDH, Apple CryptoKit, and some TLS implementations. Essentially identical to Concat KDF but with ANSI EC focus.", "mental_model" => "ANSI X9.63 ECDH hash KDF -- ECIES/Apple CryptoKit standard.", "purpose" => ["ecies kdf", "ansi x9.63 ecdh kdf"], "good_for" => ["ecies key derivation", "apple cryptokit ecdh", "ansi x9.63 compliance"], "avoid_for" => ["new designs (hkdf preferred)"], "pros" => ["ansi x9.63 standard", "ecies standard kdf", "apple cryptokit"], "cons" => ["concat kdf essentially identical", "hkdf more flexible"], "difficulty" => 1, "security" => 4, "quantum_impact" => "SHA-256 ~128-bit PQ.", "post_quantum_status" => 4, "example" => ["scenario" => "ECIES key derivation X9.63", "input" => ["Z" => "ecdh shared secret", "SharedInfo" => "optional context", "L" => "32"], "output" => ["key_material" => "32-byte derived key"]], "flow" => ["K(i) = SHA(Z || counter_i || SharedInfo)", "counter starts at 0x00000001"], "related" => ["concat-kdf", "hkdf", "kda-onestep"]],
        ["algo" => 365, "uuid" => "5c89f5", "name" => "noise-kdf", "type" => "kdf", "status" => "active", "title" => "Noise KDF", "description_md" => "Noise KDF (HKDF variant) is the key derivation mechanism used in the Noise Protocol Framework. Uses HKDF with domain separation to derive chaining keys and handshake/transport keys.\n\nNoise KDF is used in WireGuard, Signal (as base), WhatsApp, and any application built on the Noise Protocol Framework. The HKDF function is called with specific output count to derive 2 or 3 keys simultaneously.", "mental_model" => "HKDF-based Noise Protocol KDF -- WireGuard, Signal, WhatsApp key derivation.", "purpose" => ["noise protocol key derivation"], "good_for" => ["wireguard", "signal noise", "whatsapp encryption"], "avoid_for" => ["non-noise-protocol (use hkdf directly)"], "pros" => ["noise protocol standard", "2 or 3 key simultaneous derivation", "forward secrecy"], "cons" => ["noise-protocol-specific formatting"], "difficulty" => 2, "security" => 5, "quantum_impact" => "HKDF-SHA256 ~128-bit PQ.", "post_quantum_status" => 4, "example" => ["scenario" => "WireGuard ChainKey+TempKey derivation", "input" => ["ck" => "chaining_key", "input_key_material" => "ecdh output"], "output" => ["ck_new" => "new chaining key", "k" => "temp key"]], "flow" => ["HKDF-Temp-Keys = HKDF(salt=ck, ikm=input, info='')", "T1 = hmac(temp_key, 0x01)", "T2 = hmac(temp_key, T1||0x02)", "output ck = T1, k = T2"], "related" => ["hkdf", "kdf-tls13", "x25519"]],
        ["algo" => 366, "uuid" => "025938", "name" => "bip32-kdf", "type" => "kdf", "status" => "active", "title" => "BIP32 KDF", "description_md" => "BIP32 KDF is the hierarchical deterministic (HD) wallet key derivation defined in Bitcoin BIP32. Uses HMAC-SHA512 to derive child keys from parent extended keys with a chain code.\n\nBIP32 is used in all Bitcoin and Ethereum HD wallets (Ledger, Trezor, MetaMask). Supports hardened and non-hardened child key derivation. Combined with BIP44 for multi-coin derivation paths (m/44'/0'/0'/0/0).", "mental_model" => "HMAC-SHA512 HD wallet key derivation -- BIP32, all Bitcoin/Ethereum wallets.", "purpose" => ["hd wallet key derivation", "bitcoin/ethereum wallet"], "good_for" => ["bitcoin/eth hd wallets", "ledger/trezor", "metamask key derivation"], "avoid_for" => ["non-wallet kdf (use hkdf)"], "pros" => ["bip32 standard", "hierarchical key derivation", "hardened keys for security", "all wallets use it"], "cons" => ["bitcoin-specific design", "hardened vs non-hardened complexity"], "difficulty" => 2, "security" => 5, "quantum_impact" => "HMAC-SHA512 ~256-bit PQ. ECDSA secp256k1 broken by quantum (separate concern).", "post_quantum_status" => 4, "example" => ["scenario" => "BIP32 child key derivation m/44'/0'/0'", "input" => ["parent_key" => "xpub...", "index" => "0x80000000 (hardened)"], "output" => ["child_key" => "derived xprv"]], "flow" => ["hardened: HMAC-SHA512(chain_code, 0x00||privkey||index)", "normal: HMAC-SHA512(chain_code, pubkey||index)", "split 64 bytes: IL = child_key tweak, IR = new chain_code"], "related" => ["slip10", "hmac-sha512"]],
        ["algo" => 367, "uuid" => "4ca7d3", "name" => "slip10", "type" => "kdf", "status" => "active", "title" => "SLIP10", "description_md" => "SLIP10 is a generalization of BIP32 HD key derivation for multiple elliptic curves, defined in SLIP-0010. Supports secp256k1, NIST P-256, and ed25519. Uses HMAC-SHA512 like BIP32 but with curve-specific HMAC keys.\n\nSLIP10 is used in Trezor devices for ed25519 key derivation (Cardano, Stellar, Monero). It correctly handles ed25519 which BIP32 doesn't natively support.", "mental_model" => "BIP32 generalized to ed25519/P-256 -- SLIP10 for Trezor/Cardano/Stellar.", "purpose" => ["ed25519 hd wallet derivation", "multi-curve hd kdf"], "good_for" => ["cardano ada", "stellar xlm", "ed25519 hd wallets"], "avoid_for" => ["bitcoin/eth secp256k1 (use bip32)"], "pros" => ["ed25519 support", "multi-curve", "trezor standard"], "cons" => ["all hardened for ed25519"], "difficulty" => 2, "security" => 5, "quantum_impact" => "HMAC-SHA512 ~256-bit PQ; ed25519 broken by quantum.", "post_quantum_status" => 4, "example" => ["scenario" => "SLIP10 Cardano ed25519 key derivation", "input" => ["seed" => "mnemonics derived seed", "path" => "m/44'/1815'/0'/0/0"], "output" => ["ed25519_privkey" => "derived key"]], "flow" => ["HMAC-SHA512(b'ed25519 seed', seed) for master", "child: HMAC-SHA512(chain_code, 0x00||privkey||index)", "always hardened for ed25519"], "related" => ["bip32-kdf", "hmac-sha512"]],
        ["algo" => 368, "uuid" => "02c95c", "name" => "sskdf", "type" => "kdf", "status" => "active", "title" => "SS-KDF", "description_md" => "SS-KDF (Single-Step KDF) is the NIST SP 800-56C single-step KDF using either a hash function or HMAC as the auxiliary function. Equivalent to One-Step KDA.\n\nSS-KDF is the canonical NIST term for single-step key derivation from a shared secret. Used in NIST CAVP testing and FIPS-compliant implementations.", "mental_model" => "NIST SP 800-56C canonical name for single-step hash KDF -- same as One-Step KDA.", "purpose" => ["nist fips single-step kdf"], "good_for" => ["nist cavp compliance", "federal ecdh kdf"], "avoid_for" => ["non-compliance (use hkdf)"], "pros" => ["nist standard name", "hash or hmac backend"], "cons" => ["same as kda-onestep/concat-kdf (alias)"], "difficulty" => 1, "security" => 5, "quantum_impact" => "Hash dependent; SHA-256 ~128-bit PQ.", "post_quantum_status" => 4, "example" => ["scenario" => "NIST CAVP single-step KDF test", "input" => ["Z" => "shared secret", "OtherInfo" => "algorithm context"], "output" => ["K" => "derived key"]], "flow" => ["identical to kda-onestep counter hash"], "related" => ["kda-onestep", "concat-kdf", "hkdf"]],
        ["algo" => 369, "uuid" => "470734", "name" => "ecdh-kdf", "type" => "kdf", "status" => "active", "title" => "ECDH KDF", "description_md" => "ECDH KDF refers to the standard practice of applying a hash or HKDF to the ECDH shared secret before use. The raw ECDH output (x-coordinate of shared point) is not uniformly random and must be processed through a KDF.\n\nProperly using ECDH always requires a KDF step. RFC 8418 (Curve25519) and RFC 6278 (P-256) specify the correct KDF application. Using the raw ECDH output as a key is a critical vulnerability.", "mental_model" => "ECDH output must always be processed through a KDF -- raw x-coord is not a key.", "purpose" => ["ecdh output key derivation"], "good_for" => ["ecdh post-processing", "any ecdh key agreement kdf step"], "avoid_for" => ["using raw ecdh output directly as key (vulnerability)"], "pros" => ["corrects ecdh output non-uniformity", "standard ecdh+kdf practice"], "cons" => ["not a standalone algorithm (pairing with ecdh)"], "difficulty" => 1, "security" => 5, "quantum_impact" => "KDF side PQ-safe; ECDH itself broken by quantum.", "post_quantum_status" => 3, "example" => ["scenario" => "ECDH P-256 key agreement with KDF", "input" => ["shared_point_x" => "ecdh x-coordinate", "info" => "context string"], "output" => ["session_key" => "hkdf derived from x"]], "flow" => ["compute shared point Z = d_A * Q_B", "extract x-coordinate", "KDF(x, salt, info) -> session key"], "related" => ["hkdf", "x963-kdf", "concat-kdf"]],
        ["algo" => 370, "uuid" => "a4a7eb", "name" => "cmkdf", "type" => "kdf", "status" => "active", "title" => "CMKDF", "description_md" => "CMKDF (Concatenation-based Multi-Purpose KDF) is a specialized key derivation function for deriving multiple independent keys from a single master key using labeled HMAC computations.\n\nCMKDF is used in enterprise key management systems (KMS) and hardware security modules (HSMs) to derive multiple purpose-specific keys from a single root key without exposing the root key.", "mental_model" => "Labeled HMAC multi-purpose KDF for enterprise KMS subkey derivation.", "purpose" => ["enterprise kms subkey derivation"], "good_for" => ["hsm multi-purpose kdf", "enterprise kms labeled keys"], "avoid_for" => ["protocol kdf (use hkdf)"], "pros" => ["multi-purpose labeled derivation", "enterprise kms standard"], "cons" => ["enterprise-specific", "hkdf covers same use case"], "difficulty" => 2, "security" => 5, "quantum_impact" => "HMAC dependent; SHA-256 ~128-bit PQ.", "post_quantum_status" => 4, "example" => ["scenario" => "HSM multi-key derivation", "input" => ["master_key" => "root key", "label" => "encryption_key_2025"], "output" => ["derived_key" => "HMAC(master, label)"]], "flow" => ["K_purpose = HMAC-SHA256(master_key, purpose_label)", "independent labels produce independent keys"], "related" => ["hkdf", "kdf-sp800-108"]],
        ["algo" => 371, "uuid" => "3cbf7c", "name" => "me-kdf", "type" => "kdf", "status" => "active", "title" => "ME-KDF", "description_md" => "ME-KDF (Multi-Extract KDF) is a KDF design for combining multiple entropy sources into a single pseudorandom key. Used in entropy pooling and DRBG seeding scenarios where multiple independent entropy contributions must be combined securely.\n\nME-KDF is used in operating system entropy pools (Linux /dev/random, BSDs) and DRBG reseed operations to safely combine hardware entropy, user entropy, and previous state.", "mental_model" => "Multi-source entropy combining KDF -- OS entropy pool DRBG reseed.", "purpose" => ["entropy pool combining", "drbg reseed"], "good_for" => ["os entropy pool", "drbg reseed from multiple sources", "entropy harvesting"], "avoid_for" => ["standard protocol kdf (use hkdf)"], "pros" => ["multi-source entropy combining", "drbg reseed standard"], "cons" => ["specialized entropy pool use case"], "difficulty" => 3, "security" => 5, "quantum_impact" => "Hash dependent; designed for entropy combination not keying.", "post_quantum_status" => 4, "example" => ["scenario" => "Linux /dev/random entropy pool update", "input" => ["pool_state" => "current state", "hw_entropy" => "rdrand output", "user_entropy" => "key events"], "output" => ["new_pool_state" => "combined state"]], "flow" => ["HMAC over concatenated entropy sources", "fold into pool state", "pool used for DRBG reseed"], "related" => ["hkdf-extract", "hmac-sha256", "hkdf"]],
    ],
    "new" => [
        ["algo" => 372, "uuid" => "2fbd5b", "name" => "evp-bytestokey", "type" => "kdf", "status" => "new", "title" => "EVP_BytesToKey", "description_md" => "EVP_BytesToKey is an OpenSSL legacy KDF used to derive a key and IV from a password and salt using repeated MD5 or SHA-1 hashing. Defined in the OpenSSL documentation as a non-standard extension.\n\nEVP_BytesToKey is used in OpenSSL for PEM private key encryption (RSA keys protected with AES using a passphrase). Not a standard KDF -- weak by modern standards. Should be replaced with PBKDF2 or Argon2id for new designs.", "mental_model" => "OpenSSL legacy PEM passphrase KDF -- MD5-based, replace with PBKDF2.", "purpose" => ["openssl legacy pem passphrase kdf"], "good_for" => ["openssl legacy pem compatibility"], "avoid_for" => ["new designs (use pbkdf2 or argon2id)"], "pros" => ["openssl pem compatibility"], "cons" => ["md5 based", "not standardized", "weak KDF", "no iteration count"], "difficulty" => 1, "security" => 1, "quantum_impact" => "MD5 weak; avoid.", "post_quantum_status" => 1, "example" => ["scenario" => "OpenSSL PEM RSA key passphrase (legacy)", "input" => ["password" => "mypassword", "salt" => "8 random bytes"], "output" => ["key" => "aes-256-cbc key", "iv" => "16-byte IV"]], "flow" => ["D0 = MD5(password || salt)", "D1 = MD5(D0 || password || salt)", "key = D0 || D1, iv = from next hash"], "related" => ["pbkdf2", "argon2id", "scrypt"]],
        ["algo" => 373, "uuid" => "51fbc7", "name" => "kdf2", "type" => "kdf", "status" => "new", "title" => "KDF2", "description_md" => "KDF2 is a key derivation function from ISO 18033-2 based on hash-counter iteration: KDF2(Z, l) = H(Z || counter) where counter starts at 1. Slightly different from KDF1 (starts at 0).\n\nKDF2 is used in some ECIES implementations and ISO 18033-2 compliant cryptography. Essentially equivalent to Concat KDF/X9.63 KDF. Superseded by HKDF for new designs.", "mental_model" => "ISO 18033-2 KDF starting at counter 1 -- ECIES companion, superseded by HKDF.", "purpose" => ["iso 18033-2 ecies kdf"], "good_for" => ["iso 18033-2 ecies"], "avoid_for" => ["new designs (use hkdf)"], "pros" => ["iso 18033-2 standard", "simple counter hash"], "cons" => ["superseded by hkdf", "counter-1 vs kdf1 counter-0 only difference"], "difficulty" => 1, "security" => 3, "quantum_impact" => "Hash dependent; SHA-256 variant ~128-bit PQ.", "post_quantum_status" => 3, "example" => ["scenario" => "ISO 18033-2 ECIES KDF2", "input" => ["Z" => "shared secret", "len" => "32"], "output" => ["key_material" => "h(Z || 00000001) ||..."]], "flow" => ["counter = 00000001", "H(Z || counter) repeat until length met"], "related" => ["concat-kdf", "hkdf", "kda-onestep"]],
    ]
];
